// ═══════════════════════════════════════════════════════════════════
// HILFSFUNKTIONEN
// ═══════════════════════════════════════════════════════════════════

// Lokaler Datums-Key (YYYY-MM-DD) ohne UTC-Zeitzonenverschiebung
function datumKey(d) {
  const dt = new Date(d);
  const j = dt.getFullYear();
  const m = String(dt.getMonth() + 1).padStart(2, "0");
  const t = String(dt.getDate()).padStart(2, "0");
  return `${j}-${m}-${t}`;
}

function getPhaseVonTag(tag) {
  if (tag <= 10) return "power1";
  if (tag <= 15) return "manifestation";
  if (tag <= 19) return "power2";
  return "nurture";
}

function getRezepteFuerPhase(phaseId, maxAnzahl = 99) {
  return Object.values(REZEPTE).filter(r => r.phasen.includes(phaseId)).slice(0, maxAnzahl);
}

// Primal Menopausal Diet (Age Like a Girl): high fat, moderate protein, low carb + Knollen.
// Erkennung anhand vorhandener Rezept-Eigenschaften.
function istPrimalGeeignet(r) {
  // Desserts und Saucen sind keine eigenständigen Primal-Gerichte
  if (r.kategorie === "dessert" || r.kategorie === "sauce") return false;
  // Brühen (Kollagen) & Fermentiertes (Mikrobiom/Estrobolom) passen ideal
  if (r.kategorie === "broth" || r.kategorie === "fermented") return true;
  // Fasted Snacks sind kalorienarm/low carb → passen
  if (r.kategorie === "fasted_snack") return true;
  const stil = r.ernährungsstil || [];
  // Ketobiotic = low carb / high fat → Kern der Primal Diet (bei echten Mahlzeiten)
  if (stil.includes("ketobiotic") && (r.kategorie === "break_fast" || r.kategorie === "hormone_feasting" || r.kategorie === "ketobiotic" || r.kategorie === "hauptgericht" || r.kategorie === "fruehstueck")) return true;
  return false;
}

// Bestimmt, zu welchen Mahlzeiten-Slots ein Rezept passt: "fruehstueck", "mittag", "abend".
// Grund: Die Kategorie "break_fast" (= das Fasten brechen) enthält sowohl echte Frühstücke
// als auch herzhafte Mittag-/Abendgerichte (z.B. Gazpacho, Bowls). Darum kuratieren wir die
// Mahlzeiten-Eignung explizit, statt sie nur aus der Kategorie abzuleiten.
function mahlzeitenFuer(r) {
  const id = r.id;
  // Rezepte, die NUR als Frühstück Sinn ergeben (süß/typisches Frühstück)
  const nurFruehstueck = new Set([
    "pumpkin_pancakes", "granola_parfait", "chia_protein_bars", "quinoa_porridge",
    "protein_banana_donuts", "orange_chia_muffins",
    "li_artischocken_ruehrei", "li_beeren_walnuss_cookies", "li_quinoa_porridge", "etbd_schoko_fruehstuecksriegel",
  ]);
  // Rezepte, die zu Frühstück UND Mittag/Abend passen (leichte Eier-/Herzhaft-Gerichte)
  const flexibel = new Set([
    "tofu_scramble", "chickpea_omelet", "tortilla_espanola", "turkish_eggs",
    "soft_scrambled_eggs", "turmeric_eggs_salmon", "okonomiyaki", "spinach_frittata",
    "li_shakshuka_kraeuter_oliven",
  ]);
  if (nurFruehstueck.has(id)) return ["fruehstueck"];
  if (flexibel.has(id)) return ["fruehstueck", "mittag", "abend"];

  // Kategorie-Defaults
  switch (r.kategorie) {
    case "smoothie":       return ["fruehstueck", "mittag"]; // eher morgens/leicht
    case "fruehstueck":    return ["fruehstueck"];
    case "break_fast":     return ["mittag", "abend"]; // die restlichen break_fast = herzhafte Mahlzeiten
    case "hauptgericht":
    case "ketobiotic":
    case "hormone_feasting": return ["mittag", "abend"];
    case "fasted_snack":
    case "snack":          return ["snack"];
    case "broth":          return ["mittag", "abend"];
    case "fermented":      return ["fruehstueck", "mittag", "abend"]; // Beilage, passt überall
    default:               return ["mittag", "abend"];
  }
}

// Schlägt für einen konkreten Tagesplan-Slot ein passendes Rezept vor.
// phaseId: aktuelle Zyklusphase; slot: "Frühstück"|"Mittagessen"|"Abendessen"|"Fasted Snack"
// versatz: erlaubt "Anderes vorschlagen" (rotiert durch die Kandidaten)
// nurPrimal: im Menopause-Modus nur primal-geeignete Rezepte
function getSlotVorschlag(phaseId, slot, zyklusTag = 1, versatz = 0, nurPrimal = false, istJugendlich = false) {
  let alle = Object.values(REZEPTE).filter(r => r.phasen && r.phasen.includes(phaseId));
  if (nurPrimal) alle = alle.filter(istPrimalGeeignet);

  // Der "Fasted Snack"-Slot heißt für Jugendliche schlicht "Snack" (kein Fasten-Framing).
  // Für sie darf der Snack aus mehreren leichten Kategorien kommen, nicht nur fasted_snack.
  const snackKategorien = istJugendlich
    ? ["fasted_snack", "smoothie", "snack"]
    : ["fasted_snack"];

  // Welche Kategorien passen zu welchem Slot (in Prioritätsreihenfolge)
  const slotKategorien = {
    "Frühstück":     ["break_fast", "fruehstueck", "smoothie"],
    "Mittagessen":   phaseId === "manifestation" || phaseId === "nurture"
                        ? ["hormone_feasting", "ketobiotic", "hauptgericht"]
                        : ["ketobiotic", "hormone_feasting", "hauptgericht"],
    "Abendessen":    phaseId === "manifestation" || phaseId === "nurture"
                        ? ["hormone_feasting", "ketobiotic", "hauptgericht"]
                        : ["ketobiotic", "hormone_feasting", "hauptgericht"],
    "Fasted Snack":  snackKategorien,
  };
  const kats = slotKategorien[slot] || ["ketobiotic", "hormone_feasting"];

  // Kandidaten in Kategorie-Priorität sammeln
  let kandidaten = [];
  for (const kat of kats) {
    const inKat = alle.filter(r => r.kategorie === kat);
    kandidaten = kandidaten.concat(inKat);
  }
  // Nach echter Mahlzeiten-Eignung filtern (z.B. Gazpacho gehört nicht ins Frühstück).
  const slotMahlzeit = { "Frühstück": "fruehstueck", "Mittagessen": "mittag", "Abendessen": "abend" }[slot];
  if (slotMahlzeit) {
    const passend = kandidaten.filter(r => mahlzeitenFuer(r).includes(slotMahlzeit));
    if (passend.length) kandidaten = passend;
  }
  // Für Haupt- und Abendmahlzeiten echte Mahlzeiten bevorzugen (kein Mini-Snack)
  if (slot === "Mittagessen" || slot === "Abendessen") {
    const echte = kandidaten.filter(r => (r.kalorien || 0) >= 250);
    if (echte.length) kandidaten = echte;
  }
  if (kandidaten.length === 0) return null;

  // Mittag & Abend sollen sich möglichst unterscheiden: Abend um die Hälfte versetzen
  const slotOffset = slot === "Abendessen" ? Math.floor(kandidaten.length / 2) : 0;
  const idx = (Math.max(0, (zyklusTag || 1) - 1) + slotOffset + versatz) % kandidaten.length;
  return kandidaten[idx];
}

// Schlägt für eine Schwangerschafts-Mahlzeit ein passendes Rezept aus SCHWANGER_REZEPTE vor.
// mahlzeit: "Frühstück"|"Mittagessen"|"Abendessen"|"Snack"; versatz erlaubt "Anderes".
function getSchwangerVorschlag(mahlzeit, tag = 1, versatz = 0) {
  const mahlzeitKategorien = {
    "Frühstück":   ["fruehstueck", "smoothie"],
    "Mittagessen": ["hauptgericht"],
    "Abendessen":  ["hauptgericht"],
    "Snack":       ["snack", "suesses", "smoothie"],
  };
  const kats = mahlzeitKategorien[mahlzeit] || ["hauptgericht"];
  let kandidaten = [];
  for (const kat of kats) {
    kandidaten = kandidaten.concat(SCHWANGER_REZEPTE.filter(r => r.kategorie === kat));
  }
  if (kandidaten.length === 0) return null;
  // Abend um die Hälfte versetzen, damit Mittag & Abend sich unterscheiden
  const slotOffset = mahlzeit === "Abendessen" ? Math.floor(kandidaten.length / 2) : 0;
  const idx = (Math.max(0, (tag || 1) - 1) + slotOffset + versatz) % kandidaten.length;
  return kandidaten[idx];
}

function formatZeit(min) {
  if (min >= 120) return `${Math.floor(min / 60)}h`;
  if (min >= 60) return `${Math.floor(min / 60)}h ${min % 60 > 0 ? min % 60 + "min" : ""}`.trim();
  return `${min} min`;
}

function konsolidierteEinkaufsliste(rezeptIds, portionenMap) {
  const liste = {};
  rezeptIds.forEach(rid => {
    const r = REZEPTE[rid];
    if (!r) return;
    const faktor = (portionenMap[rid] || r.portionenBasis) / r.portionenBasis;
    r.zutaten.forEach(z => {
      const key = z.name.toLowerCase().replace(/[,().]/g, "").trim();
      const menge = z.menge * faktor;
      if (liste[key]) {
        if (liste[key].einheit === z.einheit) {
          liste[key].menge += menge;
        } else {
          liste[key].extraMengen = [...(liste[key].extraMengen || []), { menge, einheit: z.einheit }];
        }
      } else {
        liste[key] = { name: z.name, menge, einheit: z.einheit };
      }
    });
  });
  return Object.values(liste).sort((a, b) => a.name.localeCompare(b.name, "de"));
}

// Jugendgerechte Rezeptnamen: entfernt Fasten-Bezüge aus dem Anzeigenamen (11–19)
function rezeptAnzeigeName(r, istJugendlich) {
  if (!istJugendlich) return r.name;
  return r.name
    .replace(/\s*\(Fasting\)/gi, "")
    .replace(/Fasting Crackers/gi, "Knusper-Cracker")
    .replace(/\bFasting\b/gi, "")
    .replace(/\bFasten\b/gi, "")
    .replace(/\s{2,}/g, " ")
    .trim();
}

